import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getFeatured, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featured, setFeatured] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [f, c] = await Promise.all([getFeatured(), getCategories()]);
        setFeatured(f.data || []);
        setCategories(c.data || []);
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    };
    load();
  }, []);

  // Theme Variables from the template
  const colors = {
    navy: '#4a5d53',      // Forest Green
    gold: '#c2b2a3',      // Muted Sage/Gold
    cream: '#e2e4e1',     // Off-white background
    white: '#ffffff',
    grayText: '#8b9691'   // Muted gray
  };

  return (
    <div className="home">
      {/* Hero */}
      <section className="hero" style={{
        background: colors.navy, // Changed from blue gradient
        padding: '80px 40px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        minHeight: '80vh',
        position: 'relative',
        overflow: 'hidden'
      }}>
        <div className="hero-content" style={{
          color: '#ffffff',
          maxWidth: '600px',
          zIndex: 1
        }}>
          <p className="hero-sub" style={{
            color: colors.gold, // Changed from red
            fontSize: '14px',
            textTransform: 'uppercase',
            letterSpacing: '3px',
            marginBottom: '15px',
            fontWeight: '600'
          }}>New Collection 2026</p>
          <h1 style={{
            fontSize: '3.5rem',
            fontWeight: '800',
            marginBottom: '20px',
            lineHeight: '1.2',
            color: '#ffffff'
          }}>Elevate Your Style with <span style={{
            color: colors.gold, // Changed from pink gradient
            WebkitTextFillColor: 'initial', // Resetting gradient text
            background: 'none'
          }}>SAS Collection</span></h1>
          <p className="hero-desc" style={{
            color: 'rgba(255,255,255,0.7)', // Softened for the green theme
            fontSize: '1.1rem',
            lineHeight: '1.6',
            marginBottom: '30px'
          }}>Discover premium fashion for every occasion. Quality fabrics, timeless designs.</p>
          <div className="hero-btns" style={{
            display: 'flex',
            gap: '15px',
            flexWrap: 'wrap'
          }}>
            <Link to="/products" className="btn-primary btn-lg" style={{
              background: colors.gold, // Changed from pink
              color: colors.navy, // Dark text on light button
              padding: '12px 30px',
              borderRadius: '25px',
              textDecoration: 'none',
              fontWeight: '600',
              transition: 'all 0.3s ease',
              display: 'inline-block'
            }}>Shop Now</Link>
            <Link to="/products?isFeatured=true" className="btn-ghost btn-lg" style={{
              background: 'transparent',
              color: '#ffffff',
              padding: '12px 30px',
              borderRadius: '25px',
              textDecoration: 'none',
              fontWeight: '600',
              border: '2px solid rgba(255,255,255,0.3)',
              transition: 'all 0.3s ease',
              display: 'inline-block'
            }}>View Collection</Link>
          </div>
        </div>
        <div className="hero-image" style={{
          flex: '1',
          minHeight: '400px',
          background: 'url("https://images.unsplash.com/photo-1490481651871-ab68de25d43d?w=800") center/cover',
          borderRadius: '20px',
          position: 'relative',
          display: 'none'
        }}
        onLoad={(e) => { e.target.style.display = 'block'; }}
        >
          <div className="hero-badge" style={{
            position: 'absolute',
            top: '20px',
            right: '20px',
            background: colors.gold, // Changed from pink
            color: colors.navy,
            padding: '10px 20px',
            borderRadius: '25px',
            fontWeight: '700',
            fontSize: '0.875rem',
            letterSpacing: '1px',
            boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
          }}>New Arrivals</div>
        </div>
      </section>

      {/* Categories */}
      <section className="section" style={{
        padding: '80px 40px',
        maxWidth: '1400px',
        margin: '0 auto',
        backgroundColor: colors.cream // Changed from pure white
      }}>
        <div className="section-header" style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '40px'
        }}>
          <h2 style={{
            fontSize: '2.5rem',
            fontWeight: '800',
            color: colors.navy, // Changed from blue-black
            margin: '0'
          }}>Shop by Category</h2>
          <Link to="/products" style={{
            color: colors.navy,
            textDecoration: 'none',
            fontWeight: '600',
            fontSize: '1.1rem'
          }}>View All →</Link>
        </div>
        <div className="category-grid" style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
          gap: '20px',
          marginBottom: '40px'
        }}>
          {['Men', 'Women', 'Kids', 'Accessories', 'Footwear', 'Sale'].map(cat => (
            <Link to={`/products?category=${cat}`} key={cat} className="category-card" style={{
              position: 'relative',
              borderRadius: '12px',
              overflow: 'hidden',
              background: '#ffffff',
              textDecoration: 'none',
              transition: 'all 0.3s ease',
              aspectRatio: '1',
              boxShadow: '0 2px 10px rgba(0,0,0,0.05)',
              cursor: 'pointer'
            }}>
              <div className="category-icon" style={{ width: '100%', height: '100%' }}>
                <img 
                  src={
                    cat === 'Men' ? 'https://images.unsplash.com/photo-1490578474895-699cd4e2cf59?w=400' : 
                    cat === 'Women' ? 'https://images.unsplash.com/photo-1483985988355-763728e1935b?w=400' : 
                    cat === 'Kids' ? 'https://images.unsplash.com/photo-1519238263530-99bdd11df2ea?w=400' : 
                    cat === 'Accessories' ? 'https://images.unsplash.com/photo-1606760227091-3dd870d97f1d?w=400' : 
                    cat === 'Footwear' ? 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400' : 
                    'https://images.unsplash.com/photo-1470309864661-68328b2cd0a5?w=400'
                  } 
                  alt={cat}
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                />
              </div>
              <span style={{
                position: 'absolute',
                bottom: '0',
                left: '0',
                right: '0',
                padding: '15px',
                background: 'linear-gradient(to top, rgba(74, 93, 83, 0.9), transparent)', // Dark green gradient
                color: '#ffffff',
                fontWeight: '700',
                fontSize: '1.1rem',
                textAlign: 'center'
              }}>{cat}</span>
            </Link>
          ))}
        </div>
      </section>

      {/* Featured */}
      <section className="section" style={{
