      {/* Promo Banner */}
      <section className="promo-banner" style={{
        background: colors.navy, // Changed from dark blue
        color: '#ffffff',
        textAlign: 'center',
        padding: '80px 40px'
      }}>
        <div className="promo-content">
          <h2 style={{
            fontSize: '2.5rem',
            fontWeight: '800',
            marginBottom: '15px'
          }}>Get 20% Off Your First Order</h2>
          <p style={{
            fontSize: '1.2rem',
            color: colors.cream,
            marginBottom: '30px'
          }}>Use code <strong style={{
            backgroundColor: colors.gold,
            padding: '4px 12px',
            borderRadius: '6px',
            color: colors.navy,
            fontWeight: '700'
          }}>WELCOME20</strong> at checkout</p>
          <Link to="/register" className="btn-primary" style={{
            background: colors.gold,
            color: colors.navy,
            padding: '12px 30px',
            borderRadius: '25px',
            textDecoration: 'none',
            fontWeight: '600',
            display: 'inline-block'
          }}>Sign Up & Save</Link>
        </div>
      </section>

      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
